/**
 * Integration tests for file modification workflow
 * Tests the complete flow from file reading to modification and backup
 */

import { jest } from '@jest/globals';
import FileModifier from '../src/modifier/FileModifier.js';
import FileSystemManager from '../src/filesystem/FileSystemManager.js';
import fs from 'fs/promises';
import path from 'path';
import os from 'os';

describe('File Modification Workflow Integration', () => {
  let tempDir;
  let fileSystemManager;
  let fileModifier;

  beforeEach(async () => {
    // Create temporary directory for test files
    tempDir = await fs.mkdtemp(path.join(os.tmpdir(), 'codestral-filemod-test-'));
    fileSystemManager = new FileSystemManager(tempDir);
    fileModifier = new FileModifier(fileSystemManager);
  });

  afterEach(async () => {
    // Clean up temporary directory
    try {
      await fs.rm(tempDir, { recursive: true, force: true });
    } catch (error) {
      // Ignore cleanup errors
    }
  });

  describe('Single File Modification', () => {
    it('should modify a file with preview and backup', async () => {
      // Setup: Create test file
      const testFile = 'test.js';
      const originalContent = 'const x = 1;\nconsole.log(x);';
      const newContent = 'const x = 42;\nconsole.log(x);';

      await fs.writeFile(path.join(tempDir, testFile), originalContent);

      // Step 1: Generate diff preview
      const diff = fileModifier.generateDiff(originalContent, newContent);
      expect(diff.patches).toContain('-const x = 1;');
      expect(diff.patches).toContain('+const x = 42;');

      // Step 2: Preview changes
      const preview = await fileModifier.previewChanges([{
        filePath: testFile,
        newContent,
        description: 'Update variable value'
      }]);

      expect(preview.previews).toHaveLength(1);
      expect(preview.previews[0].diff.patches).toContain('const x = 42');

      // Step 3: Apply changes with backup
      const result = await fileModifier.applyChanges([{
        filePath: testFile,
        newContent,
        description: 'Update variable value'
      }], true);

      expect(result.success).toBe(true);
      expect(result.results).toHaveLength(1);
      expect(result.backups).toBeDefined();

      // Verify file was modified
      const actualContent = await fs.readFile(path.join(tempDir, testFile), 'utf8');
      expect(actualContent).toBe(newContent);

      // Verify backup exists
      expect(result.backups).toHaveLength(1);
      expect(result.backups[0].filePath).toBe(testFile);
    });

    it('should handle modification validation errors', async () => {
      // Try to apply changes with missing newContent
      await expect(fileModifier.applyChanges([{
        filePath: 'test.js'
        // Missing newContent
      }], true)).rejects.toThrow('Missing newContent');
    });

    it('should rollback changes when requested', async () => {
      const testFile = 'test.js';
      const originalContent = 'const x = 1;';
      const newContent = 'const x = 42;';

      await fs.writeFile(path.join(tempDir, testFile), originalContent);

      // Apply changes
      const result = await fileModifier.applyChanges([{
        filePath: testFile,
        originalContent,
        newContent,
        description: 'Update variable'
      }], true);

      expect(result.success).toBe(true);

      // Rollback changes
      const rollbackResult = await fileModifier.rollback(testFile);
      expect(rollbackResult.success).toBe(true);

      // Verify file was restored
      const restoredContent = await fs.readFile(path.join(tempDir, testFile), 'utf8');
      expect(restoredContent).toBe(originalContent);
    });
  });

  describe('Multiple File Modifications', () => {
    it('should modify multiple files atomically', async () => {
      // Setup: Create multiple test files
      const files = [
        { name: 'file1.js', original: 'const a = 1;', modified: 'const a = 10;' },
        { name: 'file2.js', original: 'const b = 2;', modified: 'const b = 20;' },
        { name: 'file3.js', original: 'const c = 3;', modified: 'const c = 30;' }
      ];

      for (const file of files) {
        await fs.writeFile(path.join(tempDir, file.name), file.original);
      }

      // Apply changes to all files
      const changes = files.map(file => ({
        filePath: file.name,
        originalContent: file.original,
        newContent: file.modified,
        description: `Update ${file.name}`
      }));

      const result = await fileModifier.applyChanges(changes, true);

      expect(result.success).toBe(true);
      expect(result.results).toHaveLength(3);
      expect(result.backups).toHaveLength(3);

      // Verify all files were modified
      for (const file of files) {
        const content = await fs.readFile(path.join(tempDir, file.name), 'utf8');
        expect(content).toBe(file.modified);
      }
    });

    it('should handle partial failures in batch modifications', async () => {
      // Setup: Create some files
      const files = [
        { name: 'file1.js', original: 'const a = 1;', modified: 'const a = 10;' },
        { name: 'file2.js', original: 'const b = 2;', modified: 'const b = 20;' }
      ];

      // Create the files
      for (const file of files) {
        await fs.writeFile(path.join(tempDir, file.name), file.original);
      }

      // Test successful batch modification
      const changes = files.map(file => ({
        filePath: file.name,
        newContent: file.modified,
        description: `Update ${file.name}`
      }));

      const result = await fileModifier.applyChanges(changes, true);

      expect(result.success).toBe(true);
      expect(result.results.length).toBe(2);
      expect(result.filesModified).toBe(2);
    });
  });

  describe('Diff Generation and Preview', () => {
    it('should generate unified diff format', () => {
      const original = 'line1\nline2\nline3\nline4';
      const modified = 'line1\nmodified line2\nline3\nline4';

      const diff = fileModifier.generateDiff(original, modified);

      expect(diff.patches).toContain('@@');
      expect(diff.patches).toContain('-line2');
      expect(diff.patches).toContain('+modified line2');
    });

    it('should handle additions and deletions', () => {
      const original = 'line1\nline2\nline3';
      const modified = 'line1\nnew line\nline2\nline4';

      const diff = fileModifier.generateDiff(original, modified);

      expect(diff.patches).toContain('+new line');
      expect(diff.patches).toContain('-line3');
      expect(diff.patches).toContain('+line4');
    });

    it('should preview changes with statistics', async () => {
      const testFile = 'test.js';
      const original = 'const x = 1;\nconst y = 2;\nconst z = 3;';
      const modified = 'const x = 10;\nconst y = 20;\nconst z = 30;';

      await fs.writeFile(path.join(tempDir, testFile), original);

      const preview = await fileModifier.previewChanges([{
        filePath: testFile,
        originalContent: original,
        newContent: modified,
        description: 'Update all constants'
      }]);

      expect(preview.previews).toHaveLength(1);
      expect(preview.summary.filesModified).toBe(1);
      expect(preview.summary.totalAdditions).toBeGreaterThan(0);
    });
  });

  describe('Backup and Recovery', () => {
    it('should create timestamped backups', async () => {
      const testFile = 'test.js';
      const originalContent = 'original content';

      await fs.writeFile(path.join(tempDir, testFile), originalContent);

      const result = await fileModifier.applyChanges([{
        filePath: testFile,
        originalContent,
        newContent: 'modified content',
        description: 'Test change'
      }], true);

      expect(result.backups[0].backupPath).toContain('.backup');
    });

    it('should list available backups', async () => {
      const testFile = 'test.js';
      await fs.writeFile(path.join(tempDir, testFile), 'content1');

      // Create first backup
      await fileModifier.applyChanges([{
        filePath: testFile,
        originalContent: 'content1',
        newContent: 'content2',
        description: 'Change 1'
      }], true);

      // Create second backup
      await fileModifier.applyChanges([{
        filePath: testFile,
        originalContent: 'content2',
        newContent: 'content3',
        description: 'Change 2'
      }], true);

      const backups = fileModifier.getBackups();
      expect(backups.length).toBeGreaterThanOrEqual(1);
      expect(backups[0]).toHaveProperty('filePath');
      expect(backups[0]).toHaveProperty('timestamp');
      expect(backups[0]).toHaveProperty('backupPath');
    });

    it('should clean up old backups', async () => {
      const testFile = 'test.js';
      await fs.writeFile(path.join(tempDir, testFile), 'content');

      // Create multiple backups
      for (let i = 0; i < 5; i++) {
        await fileModifier.applyChanges([{
          filePath: testFile,
          originalContent: `content${i}`,
          newContent: `content${i + 1}`,
          description: `Change ${i + 1}`
        }], true);
      }

      const beforeCleanup = fileModifier.getBackups();
      expect(beforeCleanup.length).toBeGreaterThanOrEqual(1);

      // Clean up old backups (keep only 3)
      const cleanupResult = await fileModifier.cleanupOldBackups(3);
      expect(cleanupResult.success).toBe(true);

      const afterCleanup = fileModifier.getBackups();
      expect(afterCleanup.length).toBeLessThanOrEqual(beforeCleanup.length);
    });
  });

  describe('Error Handling and Edge Cases', () => {
    it('should handle permission errors gracefully', async () => {
      const testFile = 'readonly.js';
      await fs.writeFile(path.join(tempDir, testFile), 'content');

      // Make file read-only (on systems that support it)
      try {
        await fs.chmod(path.join(tempDir, testFile), 0o444);
      } catch (error) {
        // Skip test if chmod not supported
        return;
      }

      const result = await fileModifier.applyChanges([{
        filePath: testFile,
        originalContent: 'content',
        newContent: 'new content',
        description: 'Should fail'
      }], true);

      expect(result.success).toBe(false);
      expect(result.error).toBeDefined();
    });

    it('should handle concurrent modifications', async () => {
      const testFile = 'concurrent.js';
      const originalContent = 'original';

      await fs.writeFile(path.join(tempDir, testFile), originalContent);

      // Simulate concurrent modification by changing file between validation and application
      const changes = [{
        filePath: testFile,
        originalContent,
        newContent: 'modified',
        description: 'Concurrent change'
      }];

      // Start modification process
      const modificationPromise = fileModifier.applyChanges(changes, true);

      // Modify file externally while modification is in progress
      setTimeout(async () => {
        try {
          await fs.writeFile(path.join(tempDir, testFile), 'externally modified');
        } catch (error) {
          // Ignore if file is locked
        }
      }, 10);

      const result = await modificationPromise;

      // Should either succeed (if external change happened after) or fail gracefully
      if (!result.success) {
        expect(result.errors.length).toBeGreaterThan(0);
      }
    });

    it('should validate file paths for security', async () => {
      const maliciousChanges = [{
        filePath: '../../../etc/passwd',
        newContent: 'hacked',
        description: 'Malicious change'
      }];

      await expect(fileModifier.applyChanges(maliciousChanges, true))
        .rejects.toThrow('outside the root directory');
    });

    it('should handle empty and whitespace-only changes', async () => {
      const testFile = 'whitespace.js';
      const originalContent = 'line1\n\nline3';
      const newContent = 'line1\n  \nline3';

      await fs.writeFile(path.join(tempDir, testFile), originalContent);

      const result = await fileModifier.applyChanges([{
        filePath: testFile,
        originalContent,
        newContent,
        description: 'Whitespace change'
      }], true);

      expect(result.success).toBe(true);

      const actualContent = await fs.readFile(path.join(tempDir, testFile), 'utf8');
      expect(actualContent).toBe(newContent);
    });
  });

  describe('Integration with File System Manager', () => {
    it('should respect .gitignore patterns', async () => {
      // Create .gitignore
      await fs.writeFile(path.join(tempDir, '.gitignore'), 'node_modules/\n*.log\n');

      // Create ignored file
      await fs.mkdir(path.join(tempDir, 'node_modules'));
      await fs.writeFile(path.join(tempDir, 'node_modules', 'package.js'), 'ignored');

      const result = await fileModifier.applyChanges([{
        filePath: 'node_modules/package.js',
        originalContent: 'ignored',
        newContent: 'modified',
        description: 'Should be ignored'
      }], true);

      // Should either succeed (if not filtered) or fail with appropriate message
      expect(result).toBeDefined();
    });

    it('should handle binary files appropriately', async () => {
      const binaryFile = 'image.png';
      const binaryContent = Buffer.from([0x89, 0x50, 0x4E, 0x47]); // PNG header

      await fs.writeFile(path.join(tempDir, binaryFile), binaryContent);

      const result = await fileModifier.applyChanges([{
        filePath: binaryFile,
        originalContent: binaryContent.toString(),
        newContent: 'text content',
        description: 'Binary to text'
      }], true);

      // Should handle binary files appropriately (either skip or warn)
      expect(result).toBeDefined();
    });
  });
});